const logoBase64 = "data:image/jpeg;base64,";
const unitsContainer = document.getElementById("units");

function pad(num) {
  return String(num).padStart(2, "0");
}

function setDefaults() {
  const now = new Date();
  document.getElementById("date").value = `${now.getFullYear()}-${pad(now.getMonth() + 1)}-${pad(now.getDate())}`;
  document.getElementById("time").value = `${pad(now.getHours())}:${pad(now.getMinutes())}`;
}

function addUnit(data = {}) {
  const index = unitsContainer.children.length + 1;
  const card = document.createElement("div");
  card.className = "unit-card";
  card.innerHTML = `
    <div class="unit-header">
      <span>Unit ${index}</span>
      <button type="button" class="remove-unit">Remove</button>
    </div>
    <div class="unit-grid">
      <div class="field">
        <label>Unit Type</label>
        <select class="unitType">
          <option>Trailer</option>
          <option>Tractor</option>
          <option>Forklift</option>
          <option>Other</option>
        </select>
      </div>
      <div class="field">
        <label>Unit Number</label>
        <input class="unitNumber" type="text" placeholder="104" value="${data.unitNumber || ""}" />
      </div>
      <div class="field">
        <label>Tire Size</label>
        <input class="tireSize" type="text" placeholder="11R22.5" value="${data.tireSize || ""}" />
      </div>
      <div class="field">
        <label>Position</label>
        <input class="position" type="text" placeholder="Left front" value="${data.position || ""}" />
      </div>
    </div>
    <div class="field" style="margin-top:16px;">
      <label>Other Information</label>
      <textarea class="otherInfo" placeholder="Replace blown tire, air leak, customer notes, etc.">${data.otherInfo || ""}</textarea>
    </div>
  `;

  card.querySelector(".unitType").value = data.unitType || "Trailer";
  card.querySelector(".remove-unit").addEventListener("click", () => {
    if (unitsContainer.children.length > 1) {
      card.remove();
      renumberUnits();
      updateFilenamePreview();
    }
  });

  card.querySelectorAll("input, select, textarea").forEach(el => {
    el.addEventListener("input", updateFilenamePreview);
    el.addEventListener("change", updateFilenamePreview);
  });

  unitsContainer.appendChild(card);
  updateFilenamePreview();
}

function renumberUnits() {
  [...unitsContainer.children].forEach((card, i) => {
    card.querySelector(".unit-header span").textContent = `Unit ${i + 1}`;
  });
}

function getUnits() {
  return [...unitsContainer.children].map(card => ({
    unitType: card.querySelector(".unitType").value.trim(),
    unitNumber: card.querySelector(".unitNumber").value.trim(),
    tireSize: card.querySelector(".tireSize").value.trim(),
    position: card.querySelector(".position").value.trim(),
    otherInfo: card.querySelector(".otherInfo").value.trim()
  }));
}

function cleanFilenamePart(value) {
  return (value || "")
    .replace(/[\\/:*?"<>|_\-]+/g, " ")
    .replace(/\s+/g, " ")
    .trim();
}

function formatDateForFilename(dateValue) {
  if (!dateValue) return "";
  const [year, month, day] = dateValue.split("-");
  return `${day} ${month} ${year}`;
}

function buildFilename() {
  const date = formatDateForFilename(document.getElementById("date").value);
  const customer = cleanFilenamePart(document.getElementById("customerName").value) || "Customer";
  const units = getUnits()
    .map(u => cleanFilenamePart(u.unitNumber))
    .filter(Boolean)
    .join(" ");

  return `${date} ${customer} ${units || "Unit"}.pdf`.replace(/\s+/g, " ").trim();
}

function updateFilenamePreview() {
  document.getElementById("filenamePreview").textContent = buildFilename();
}

function formatDateForPdf(dateValue) {
  if (!dateValue) return "";
  const [year, month, day] = dateValue.split("-");
  return `${day}/${month}/${year}`;
}

function formatTimeForPdf(timeValue) {
  if (!timeValue) return "";
  let [hours, minutes] = timeValue.split(":").map(Number);
  const ampm = hours >= 12 ? "PM" : "AM";
  hours = hours % 12 || 12;
  return `${hours}:${pad(minutes)} ${ampm}`;
}

function addText(doc, label, value, x, y) {
  doc.setFont("helvetica", "bold");
  doc.text(`${label}:`, x, y);
  doc.setFont("helvetica", "normal");
  doc.text(value || "", x + 44, y);
}

function generatePdf() {
  const { jsPDF } = window.jspdf;
  const doc = new jsPDF({ unit: "pt", format: "letter" });

  const date = formatDateForPdf(document.getElementById("date").value);
  const time = formatTimeForPdf(document.getElementById("time").value);
  const callTakenBy = document.getElementById("callTakenBy").value;
  const serviceTech = document.getElementById("serviceTech").value;
  const customerName = document.getElementById("customerName").value;
  const phoneNumber = document.getElementById("phoneNumber").value;
  const serviceLocation = document.getElementById("serviceLocation").value;
  const driverName = document.getElementById("driverName").value;
  const driverPhone = document.getElementById("driverPhone").value;
  const poNumber = document.getElementById("poNumber").value;
  const units = getUnits();

  doc.addImage(logoBase64, "JPEG", 40, 30, 180, 48);
  doc.setFont("helvetica", "bold");
  doc.setFontSize(20);
  doc.text("ON-ROAD SERVICE CALL", 306, 62, { align: "center" });

  doc.setDrawColor(246, 196, 0);
  doc.setLineWidth(4);
  doc.line(40, 95, 572, 95);

  doc.setFontSize(11);
  let y = 125;
  addText(doc, "Date", date, 40, y);
  addText(doc, "Time", time, 330, y);
  y += 24;
  addText(doc, "Call Taken By", callTakenBy, 40, y);
  addText(doc, "Service Tech", serviceTech, 330, y);

  y += 32;
  doc.setDrawColor(0, 0, 0);
  doc.setLineWidth(0.7);
  doc.line(40, y, 572, y);
  y += 28;

  addText(doc, "Customer Name", customerName, 40, y); y += 24;
  addText(doc, "Phone Number", phoneNumber, 40, y); y += 24;
  addText(doc, "Service Location", serviceLocation, 40, y); y += 24;
  addText(doc, "Driver Name", driverName, 40, y); y += 24;
  addText(doc, "Driver Phone", driverPhone, 40, y); y += 24;
  addText(doc, "PO Number", poNumber, 40, y); y += 34;

  doc.setFont("helvetica", "bold");
  doc.setFontSize(13);
  doc.text("Units Requiring Service", 40, y);
  y += 16;

  const headers = ["Unit Type", "Unit Number", "Tire Size", "Position", "Other Info"];
  const widths = [80, 90, 90, 100, 172];
  let x = 40;

  doc.setFillColor(230, 230, 230);
  doc.rect(40, y, 532, 24, "F");
  doc.setFontSize(9);
  headers.forEach((h, i) => {
    doc.setFont("helvetica", "bold");
    doc.text(h, x + 5, y + 16);
    x += widths[i];
  });

  y += 24;
  doc.setFont("helvetica", "normal");

  units.forEach(unit => {
    if (y > 720) {
      doc.addPage();
      y = 50;
    }

    const rowHeight = 42;
    x = 40;
    doc.rect(40, y, 532, rowHeight);

    const values = [unit.unitType, unit.unitNumber, unit.tireSize, unit.position, unit.otherInfo];
    values.forEach((v, i) => {
      if (i > 0) doc.line(x, y, x, y + rowHeight);
      const text = doc.splitTextToSize(v || "", widths[i] - 10);
      doc.text(text, x + 5, y + 15);
      x += widths[i];
    });

    y += rowHeight;
  });

  doc.save(buildFilename());
}

function clearForm() {
  document.querySelectorAll("input, textarea").forEach(el => el.value = "");
  unitsContainer.innerHTML = "";
  setDefaults();
  addUnit();
  updateFilenamePreview();
}

document.getElementById("addUnitBtn").addEventListener("click", () => addUnit());
document.getElementById("generatePdfBtn").addEventListener("click", generatePdf);
document.getElementById("clearBtn").addEventListener("click", clearForm);

document.querySelectorAll("input").forEach(el => {
  el.addEventListener("input", updateFilenamePreview);
  el.addEventListener("change", updateFilenamePreview);
});

setDefaults();
addUnit();
updateFilenamePreview();
